using System;

class Program
{
    // Iteratif yontem
    static long FibonacciIterative(int n)
    {
        if (n <= 1) return n;

        long a = 0, b = 1;
        for (int i = 2; i <= n; i++)
        {
            long temp = a + b;
            a = b;
            b = temp;
        }
        return b;
    }

    // Recursive yontem
    static long FibonacciRecursive(int n)
    {
        if (n <= 1) return n;
        return FibonacciRecursive(n - 1) + FibonacciRecursive(n - 2);
    }

    static void Main()
    {
        Console.WriteLine("Iteratif Fibonacci (0-10):");
        for (int i = 0; i <= 10; i++)
        {
            Console.Write(FibonacciIterative(i) + " ");
        }
        Console.WriteLine();

        Console.WriteLine("\nRecursive Fibonacci (0-10):");
        for (int i = 0; i <= 10; i++)
        {
            Console.Write(FibonacciRecursive(i) + " ");
        }
        Console.WriteLine();

        Console.WriteLine("\n20. Fibonacci sayisi: " + FibonacciIterative(20));
    }
}
